     1→import ts from 'typescript';
     2→import { glob, fs, chalk } from 'zx';
     3→import path from 'path';
     4→import { ScriptConfig } from './config';
     5→import isVersionGreater from 'semver/functions/gt';
     6→
     7→/**
     8→ * create a terminal/CLI clickable link
     9→ * @param input
    10→ */
    11→export function createCLILink(input: {
    12→  line: number;
    13→  character: number;
    14→  filePath: string;
    15→  title: string;
    16→}) {
    17→  const { character, filePath, line, title } = input;
    18→
    19→  let targetUri = `file://${filePath}`;
    20→
    21→  if (line) {
    22→    targetUri += `:${line}`;
    23→    if (character) {
    24→      targetUri += `:${character}`;
    25→    }
    26→  }
    27→
    28→  const prefix = `\x1b]8;;${targetUri}\x07`;
    29→  const suffix = `\x1b]8;;\x07`;
    30→
    31→  return `${prefix}${title}${suffix}`;
    32→}
    33→
    34→/**
    35→ * Write text to the terminal.
    36→ * This is util because console.log is async
    37→ * @param value
    38→ * @param output
    39→ */
    40→export function logSync(
    41→  value: string,
    42→  output: 'stdout' | 'stderr' | 'warning' = 'stdout',
    43→) {
    44→  let formatted = value.endsWith('\n') ? value : value + '\n';
    45→  if (output === 'stderr') formatted = chalk.red(formatted);
    46→  if (output === 'warning') {
    47→    formatted = chalk.bgBlackBright(chalk.yellow(formatted));
    48→  }
    49→  const channel = output === 'warning' ? 'stdout' : output;
    50→  fs.writeSync(process[channel].fd, formatted);
    51→}
    52→
    53→export function escapeRegExp(string: string) {
    54→  return (
    55→    string
    56→      // https://github.com/sindresorhus/escape-string-regexp/blob/main/index.js
    57→      .replace(/[|\\{}()[\]^$+*?.]/g, '\\$&')
    58→      .replace(/-/g, '\\x2d')
    59→  );
    60→}
    61→
    62→// https://stackoverflow.com/a/7616484
    63→export function hashString(str: string) {
    64→  if (str.length === 0) return '0';
    65→  let hash = 0;
    66→  for (let i = 0; i < str.length; i++) {
    67→    const char = str.charCodeAt(i);
    68→    hash = (hash << 5) - hash + char;
    69→    hash |= 0;
    70→  }
    71→  return hash.toString(36).replace(/^-/, '');
    72→}
    73→
    74→// Throw an error if the valor is falsy
    75→export function invariant(
    76→  value: unknown,
    77→  error = 'Expected value to not be empty.',
    78→): asserts value {
    79→  if (!value) throw new Error(error);
    80→}
    81→
    82→export function lastElement<T>(parts: T[]): T {
    83→  invariant(parts.length, 'Expected array to not be empty');
    84→  return parts[parts.length - 1];
    85→}
    86→
    87→// Search on files to imports matching a specific string
    88→export namespace DiscoveryUsedImports {
    89→  type Params = {
    90→    // the root folder to be scanned
    91→    folder: string;
    92→    // glob import declarations to be included
    93→    match: string[];
    94→    // glob imports to be ignored
    95→    ignore?: string[];
    96→  };
    97→
    98→  export function find(params: Params): string[] {
    99→    const { folder } = params;
   100→    const resolvedFolder = path.resolve(folder);
   101→    const filePaths = glob.sync(`${resolvedFolder}/**/*.{ts,tsx}`);
   102→    const elements = new Set<string>();
   103→
   104→    const testImport = createMatcher(params);
   105→
   106→    for (const filePath of filePaths) {
   107→      const fileContent = fs.readFileSync(filePath, 'utf8');
   108→
   109→      const sourceFile = ts.createSourceFile(
   110→        filePath,
   111→        fileContent,
   112→        ts.ScriptTarget.Latest,
   113→        true,
   114→      );
   115→
   116→      function visit(node: ts.Node) {
   117→        const specifier = ts.isImportDeclaration(node)
   118→          ? ts.isStringLiteral(node.moduleSpecifier)
   119→            ? node.moduleSpecifier.text
   120→            : null
   121→          : null;
   122→        if (testImport(specifier)) elements.add(specifier);
   123→        ts.forEachChild(node, visit);
   124→      }
   125→
   126→      visit(sourceFile);
   127→    }
   128→
   129→    return [...elements];
   130→  }
   131→}
   132→
   133→// Creates a tester function from a glob pattern
   134→export function createMatcher(params: {
   135→  match: string | string[];
   136→  ignore?: string | string[];
   137→}) {
   138→  type NullableString = string | null | undefined;
   139→
   140→  function getPattern(glob: string) {
   141→    assertString(glob);
   142→
   143→    let regexString = '';
   144→    let i = 0;
   145→    let segment = '';
   146→
   147→    while (i < glob.length) {
   148→      const char = glob[i];
   149→
   150→      if (char === '*') {
   151→        if (segment) {
   152→          regexString += escapeRegExp(segment);
   153→          segment = '';
   154→        }
   155→
   156→        if (glob[i + 1] === '*') {
   157→          // Here, the current char is '*' and the next one is '*', then
   158→          // it is '**': match everything including slashes
   159→          regexString += '.*';
   160→          i += 2;
   161→        } else {
   162→          regexString += '[^/]*';
   163→          i++;
   164→        }
   165→      } else {
   166→        segment += char;
   167→        i++;
   168→      }
   169→    }
   170→
   171→    if (segment) {
   172→      regexString += escapeRegExp(segment);
   173→    }
   174→
   175→    return regexString;
   176→  }
   177→
   178→  function getTest(glob: NullableString | NullableString[]) {
   179→    let array = (Array.isArray(glob) ? glob : [glob]).filter(Boolean);
   180→    if (!array || !array.length) return () => false;
   181→    const pattern = array.map(glob => getPattern(glob!)).join('|');
   182→    const regex = new RegExp(`^${pattern}$`);
   183→    return function test(value: NullableString) {
   184→      if (typeof value !== 'string') return false;
   185→      return regex.test(value);
   186→    };
   187→  }
   188→
   189→  const testInclude = getTest(params.match);
   190→  const testExclude = getTest(params.ignore);
   191→
   192→  return function test(value: NullableString): value is string {
   193→    if (typeof value !== 'string') return false;
   194→    return testInclude(value) && !testExclude(value);
