   153→
   154→  // Used to extract types from a source file.
   155→  function FileTypesExtractor(
   156→    sourceFile: ts.SourceFile,
   157→    moduleSymbol: ts.Symbol,
   158→  ) {
   159→    const processed = new Set<ts.Symbol>(); // to avoid processing the same symbol twice.
   160→
   161→    const bodyPartBySymbol = new Map<ts.Symbol, string>();
   162→
   163→    // A typescript `symbol` represents a named declaration like a variable or
   164→    // interface. Here we recursively scan and extract types as a strings.
   165→    function scan(symbol: ts.Symbol) {
   166→      if (!symbol) return;
   167→      if (processed.has(symbol)) return;
   168→      processed.add(symbol);
   169→
   170→      const declaration =
   171→        symbol.valueDeclaration ?? // things that have a "value" at runtime (vars, functions).
   172→        symbol.declarations?.[0]; // things that are just types (interfaces, type aliases).
   173→
   174→      if (!declaration) return;
