   229→      // handle `export const foo = ...`
   230→      bodyPartBySymbol.set(
   231→        symbol,
   232→        `export declare const ${symbol.getName()}: ${typeText};`,
   233→      );
   234→    }
   235→
   236→    CHECKER.getExportsOfModule(moduleSymbol).forEach(scan);
   237→
   238→    let { imports, transformedBody } = ExtractInlineImports({
   239→      parentFileName: sourceFile.fileName,
   240→      code: [...bodyPartBySymbol.values()].join('\n'),
   241→    });
   242→
   243→    ts.forEachChild(sourceFile, node => {
   244→      if (ts.isImportDeclaration(node)) {
   245→        ParseImportDeclaration(sourceFile, node).forEach(imported => {
   246→          const list = imports.get(imported.fileName) ?? new Map();
   247→          list.set(imported.symbol, imported);
   248→          imports.set(imported.fileName, list);
   249→        });
   250→      }
   251→    });
   252→
   253→    return {
   254→      imports,
   255→      body: transformedBody,
   256→    };
   257→  }
   258→
   259→  function isIdentifierOfAType(identifier: ts.Identifier) {
   260→    const symbol = CHECKER.getSymbolAtLocation(identifier);
   261→    if (!symbol) return false;
   262→    const flags = CHECKER.getAliasedSymbol(symbol).getFlags();
   263→    return flags & ts.SymbolFlags.Type && !(flags & ts.SymbolFlags.Value);
   264→  }
   265→
   266→  function ParseImportDeclaration(
   267→    sourceFile: ts.SourceFile,
   268→    declaration: ts.ImportDeclaration,
   269→  ): Imported[] {
   270→    const namedBindings = declaration.importClause?.namedBindings;
   271→
   272→    const importedSymbols: string[] = [];
   273→
   274→    const defaultImportedName = declaration.importClause?.name?.text;
   275→
   276→    if (
   277→      declaration.importClause?.name &&
   278→      isIdentifierOfAType(declaration.importClause.name)
   279→    ) {
   280→      importedSymbols.push(declaration.importClause.name.text);
   281→    }
   282→
   283→    if (namedBindings && ts.isNamedImports(namedBindings)) {
   284→      namedBindings.elements.forEach(element => {
   285→        if (!isIdentifierOfAType(element.name)) return;
   286→        const name = element.name.text;
   287→        importedSymbols.push(name);
   288→      });
   289→    }
   290→
   291→    const specifier = declaration.moduleSpecifier
   292→      .getText(sourceFile)
   293→      .slice(1, -1);
   294→
   295→    const { fileName, destinationSpecifier } = ParseModuleInfo(
   296→      specifier,
   297→      sourceFile.fileName,
   298→    );
   299→
   300→    return importedSymbols.map((symbol): Imported => {
   301→      return {
   302→        symbol,
   303→        fileName,
   304→        destinationSpecifier,
   305→        specifier,
   306→        node: declaration,
   307→        isDefaultImport: symbol === defaultImportedName,
   308→      };
   309→    });
   310→  }
   311→
   312→  // resolve file locations, path alias, etc
   313→  function ParseModuleInfo(specifier: string, fromPath: string): ModuleInfo {
   314→    const fileName =
   315→      ts.resolveModuleName(
   316→        specifier,
   317→        fromPath,
   318→        PROGRAM.getCompilerOptions(),
   319→        HOST,
   320→      ).resolvedModule?.resolvedFileName ?? '';
   321→
   322→    if (!fileName) {
   323→      logSync(`Failed to resolve "${specifier}" from ${fromPath}.`, 'stderr');
   324→    }
   325→
   326→    const isNodeModule = fileName.includes('/node_modules/');
   327→    let packageName = '';
   328→
   329→    const pathFromNodeModules = (() => {
   330→      if (!isNodeModule) return null;
   331→
   332→      let nodeModulePath = normalizePath(fileName.split('/node_modules/')[1]);
   333→
   334→      packageName = nodeModulePath
   335→        .split('/')
   336→        .slice(
   337→          0,
   338→          // for scoped packages (@scope/package_name), we extract 2 parts
   339→          nodeModulePath.startsWith('@') ? 2 : 1,
   340→        )
   341→        .join('/');
   342→
   343→      return nodeModulePath;
   344→    })();
   345→
   346→    const genericSpecifier = normalizePath(
   347→      (() => {
   348→        const isProjectFile = fileName.startsWith(PROJECT_PATH);
   349→        const isLocalFile = !isProjectFile && fileName.startsWith(CWD);
   350→
   351→        const scope = isLocalFile ? '@generated_local' : '@generated';
   352→
   353→        if (!isLocalFile && !isProjectFile) {
   354→          return path.join(
   355→            scope,
   356→            // masking the file path to not include the
   357→            // full path (with username, etc)
   358→            hashString(path.dirname(fileName)),
   359→            path.basename(fileName),
   360→          );
   361→        }
   362→
   363→        const resultPath = lastElement(
   364→          isProjectFile ? fileName.split(PROJECT_PATH) : fileName.split(CWD),
   365→        );
   366→
   367→        return path.join(scope, resultPath);
   368→      })(),
   369→    );
   370→
   371→    const isSameNpmScope = Boolean(
   372→      packageName &&
   373→        PACKAGE_NAMESPACE &&
   374→        packageName.startsWith(PACKAGE_NAMESPACE),
   375→    );
   376→
   377→    let destinationSpecifier = pathFromNodeModules ?? genericSpecifier;
   378→
   379→    if (MODULES_PARAM.includes(specifier)) {
   380→      destinationSpecifier = specifier;
   381→    }
   382→
   383→    let partial: Omit<ModuleInfo, 'sourceFile'> = {
   384→      pathFromNodeModules,
   385→      genericSpecifier,
   386→      destinationSpecifier,
   387→      fileName,
   388→      isNodeModule,
   389→      packageName,
   390→      isSameNpmScope,
   391→      ignore: false,
   392→    };
   393→
   394→    let moduleInfo = Object.defineProperties(partial, {
   395→      sourceFile: {
   396→        get() {
   397→          const sourceFile = PROGRAM.getSourceFile(fileName);
   398→          invariant(sourceFile, `Failed to resolve ${fileName}`);
   399→          return sourceFile;
   400→        },
   401→      },
   402→    }) as ModuleInfo;
   403→
   404→    if (TRANSFORM_MODULE && !VISITED.has(fileName)) {
   405→      const transformed = TRANSFORM_MODULE(moduleInfo);
   406→      if (transformed === null) {
   407→        moduleInfo.ignore = true;
   408→      } else {
   409→        moduleInfo = transformed;
   410→      }
   411→    }
   412→
   413→    const cachedData = MODULE_INFO_MAP.get(fileName);
   414→    const oldId = cachedData?.destinationSpecifier;
   415→    const newId = moduleInfo.destinationSpecifier;
   416→    if (oldId && oldId !== newId) {
   417→      // if the same module is imported with different identifiers,
   418→      // we use the first one.
   419→      return cachedData;
   420→    }
   421→    MODULE_INFO_MAP.set(fileName, moduleInfo);
   422→    return moduleInfo;
   423→  }
   424→
   425→  /**
   426→   * The entry/recursive part - it visits a module file, extracts its types,
   427→   * and then recursively visits all of its local imports.
   428→   * @param specifier Module import string (e.g., '~/components/Button').
   429→   * @param parentFilePath File that is importing this module.
   430→   * @param level The current recursion depth.
   431→   */
   432→  function* Visit(
   433→    specifier: string,
   434→    parentFilePath: string,
   435→    level: number,
   436→  ): Generator<ResultingModuleDeclaration> {
   437→    try {
   438→      if (level > MAX_DEPTH) return;
   439→
   440→      // real file path on disk.
   441→      const moduleInfo = ParseModuleInfo(specifier, parentFilePath);
   442→      if (moduleInfo.ignore) return;
   443→
   444→      const { fileName, sourceFile } = moduleInfo;
   445→
   446→      // check for already processed this exact import path.
   447→      if (VISITED.has(fileName)) return;
   448→      VISITED.add(fileName);
   449→
   450→      const moduleSymbol = CHECKER.getSymbolAtLocation(sourceFile);
   451→      if (!moduleSymbol) return;
   452→
   453→      logSync(
   454→        chalk.gray(
   455→          `‣ processing ${path.relative(PROJECT_PATH, sourceFile.fileName)}`,
   456→        ),
   457→      );
   458→
   459→      // extractor to get all the type information from the file.
   460→      const file = FileTypesExtractor(sourceFile, moduleSymbol);
   461→
   462→      // recursively visit all the used imports in this file.
   463→      for (let [importedModulePath, imported] of file.imports) {
   464→        const head: string[] = [];
   465→
   466→        imported.forEach(el => {
   467→          const { symbol, destinationSpecifier } = el;
   468→
   469→          if (symbol === 'Omit' && destinationSpecifier === 'react-redux') {
   470→            // hotfix importing Omit from 'react-redux'
   471→            return;
   472→          }
   473→
   474→          const regex = new RegExp(`\\b${escapeRegExp(el.symbol)}\\b`);
   475→          if (!regex.test(file.body)) return;
   476→
   477→          if (el.isDefaultImport) {
   478→            let txt = head[0] ?? '';
   479→            txt += `import ${el.symbol} from '${el.specifier}';\n`;
   480→            head[0] = txt;
   481→          } else {
   482→            let txt = head[1] ?? '';
   483→            let first = !txt;
   484→            if (first) txt = `import {`;
   485→            txt += first ? el.symbol : `,${el.symbol}`;
   486→            head[1] = txt;
   487→          }
   488→        });
   489→
   490→        let txt = head[1] ?? '';
   491→        if (txt) {
   492→          txt += `} from '${imported.values().next().value!.destinationSpecifier}';\n`;
   493→        }
   494→
   495→        yield* Visit(importedModulePath, sourceFile.fileName, level + 1);
   496→
   497→        file.body = `${txt} ${file.body}\n`;
   498→      }
   499→
   500→      yield {
   501→        ...file,
   502→        ...moduleInfo,
   503→        destinationSpecifier:
   504→          level === 0 ? specifier : moduleInfo.destinationSpecifier,
   505→      };
   506→    } catch (e: any) {
   507→      logSync(`  🐞 ${e.message}`, 'warning');
   508→      ERRORS.add(lastElement(specifier.split('/node_modules/')));
   509→      return;
   510→    }
   511→  }
   512→
   513→  // Return a typescript `Program` (Compiler)
   514→  function SetupCompiler() {
   515→    const configPath = ts.findConfigFile(
   516→      PROJECT_PATH,
   517→      ts.sys.fileExists,
   518→      'tsconfig.json',
   519→    );
   520→
   521→    invariant(
   522→      configPath,
   523→      `Could not find a valid tsconfig.json at ${PROJECT_PATH}`,
   524→    );
   525→
   526→    const configFile = ts.readConfigFile(configPath, ts.sys.readFile);
   527→
   528→    const compilerOptions = {
   529→      ...configFile.config.compilerOptions,
   530→      noEmitOnError: false,
   531→    };
   532→
   533→    const parsedConfig = ts.parseJsonConfigFileContent(
   534→      { ...configFile.config, compilerOptions },
   535→      ts.sys,
   536→      PROJECT_PATH,
   537→    );
   538→
   539→    HOST = ts.createCompilerHost(parsedConfig.options);
   540→    PROGRAM = ts.createProgram(
   541→      parsedConfig.fileNames,
   542→      parsedConfig.options,
   543→      HOST,
   544→    );
   545→    CHECKER = PROGRAM.getTypeChecker();
   546→  }
   547→
   548→  export type Params = {
   549→    // the root directory of the project to generate typings from.
   550→    projectPath: string;
   551→
   552→    // an array of entry-point module paths to start the generation from.
   553→    modules: string[];
   554→
   555→    // how many levels of imports deep should the generator go.
   556→    maxDepth?: number;
   557→
   558→    // used to transform the final module before it's rendered.
   559→    // returning null will skip this module from output
   560→    transform?: (path: ModuleInfo) => ModuleInfo | null;
   561→
   562→    // if true, code from node_modules will not be bundled
   563→    // defaults to true
   564→    ignoreNoduleModules?: boolean;
   565→
   566→    // defaults to process.cwd()
   567→    cwd?: string;
   568→  };
   569→
   570→  export function Generate(params: Params) {
   571→    const { modules } = params;
   572→
   573→    // defining internal configuration
   574→    MODULES_PARAM = modules;
   575→    VISITED.clear();
   576→    MODULE_INFO_MAP.clear();
   577→    ERRORS.clear();
   578→    CWD = params.cwd ?? process.cwd();
   579→    PROJECT_PATH = params.projectPath;
   580→    MAX_DEPTH = params.maxDepth ?? DEFAULT_MAX_DEPTH;
   581→    TRANSFORM_MODULE = params.transform ?? null;
   582→
   583→    PACKAGE_NAME = (() => {
   584→      const jsonPath = path.resolve(CWD, 'package.json');
   585→      if (!fs.existsSync(jsonPath)) {
   586→        return logSync(`No package.json found at current working directory.`);
   587→      }
   588→      const packageJSON = fs.readJSONSync(jsonPath);
   589→      return packageJSON.name;
   590→    })();
   591→
   592→    PACKAGE_NAMESPACE = (() => {
   593→      if (!PACKAGE_NAME) return;
   594→      const parts = PACKAGE_NAME.split('/');
   595→      if (parts.length === 2) return parts[0];
   596→    })();
   597→
   598→    // start the typescript compiler API.
   599→    SetupCompiler();
   600→
   601→    let result =
   602→      [
   603→        `/* istanbul ignore file */`,
   604→        `/* Auto generated file, do not edit by hand */`,
   605→      ].join('\n') + '\n\n';
   606→
   607→    const virtualPath = path.join(PROJECT_PATH, `__source.ts`);
   608→
   609→    let count = 0;
   610→    modules.forEach(moduleToGenerate => {
   611→      // Visit recursively collect types for each
   612→      // module and its dependencies.
   613→      const moduleAndChildrenGenerator = Visit(
   614→        moduleToGenerate,
   615→        virtualPath,
   616→        0,
   617→      );
   618→      for (let module of moduleAndChildrenGenerator) {
   619→        result += `declare module '${module.destinationSpecifier}' {\n`;
   620→        result += '\n\n';
   621→        result += module.body;
   622→        result += `\n}\n\n`;
   623→        count++;
   624→      }
   625→    });
   626→
   627→    if (count) {
   628→      logSync(`\n✅ Process finished for ${count} modules.`);
   629→    }
   630→
   631→    if (ERRORS.size) {
   632→      const messages = [...ERRORS.values()].map(err => `  ‣ ${err}`).join('\n');
   633→      logSync(`  Some errors occurred at:\n${messages}`);
   634→    }
   635→
   636→    return result;
   637→  }
   638→}
   639→
   640→function normalizePath(s: string) {
   641→  return s
   642→    .replace(/^@types\//, '')
   643→    .replace(/\/index(\.(jsx|ts|tsx|js))?$/, '')
   644→    .replace(/\.d\.ts$/, '')
   645→    .replace(/\/index$/, '')
   646→    .replace(/\/src\/?$/, '');
   647→}
